SELECT MAP(ARRAY['FullServiceRestaurant', 'QuickServiceRestaurant', 'RetailStandalone', 'RetailStripmall', 'PrimarySchool', 'SecondarySchool', 'SmallOffice', 'MediumOffice', 'LargeOffice', 'SmallHotel', 'LargeHotel', 'Hospital', 'Outpatient', 'Warehouse'], ARRAY['Food', 'Food', 'Retail', 'Retail', 'School', 'School', 'Office', 'Office', 'Office', 'Lodging', 'Lodging', 'Health', 'Health', 'Warehouse'])[baseline."in.comstock_building_type"] AS simple_bldg_type, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption..kwh" * baseline.weight) AS "electricity.total.energy_consumption..kwh" FROM (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline WHERE baseline.applicability = true AND baseline.state = 'CO' GROUP BY 1 ORDER BY 1